      host: smtpIn.host != null ? smtpIn.host : currentSmtp.host,
      port: smtpIn.port != null ? smtpIn.port : currentSmtp.port,
      secure: smtpIn.secure != null ? smtpIn.secure : currentSmtp.secure,
